.mrg-cluster {
  --mrg-cluster-gap: var(--mrg-semantic-space-inline-sm);
  align-items: center;
  display: flex;
  flex-wrap: wrap;
  gap: var(--mrg-cluster-gap);
  justify-content: flex-start;
  max-inline-size: 100%;
  min-inline-size: 0;
}

.mrg-cluster > * {
  max-inline-size: 100%;
  min-inline-size: 0;
  overflow-wrap: anywhere;
}

.mrg-cluster[data-gap="none"] {
  --mrg-cluster-gap: 0px;
}

.mrg-cluster[data-gap="xs"] {
  --mrg-cluster-gap: var(--mrg-semantic-space-inline-xs);
}

.mrg-cluster[data-gap="md"] {
  --mrg-cluster-gap: var(--mrg-semantic-space-inline-md);
}

.mrg-cluster[data-gap="lg"] {
  --mrg-cluster-gap: var(--mrg-semantic-space-inline-lg);
}

.mrg-cluster[data-align="start"] {
  align-items: flex-start;
}

.mrg-cluster[data-align="end"] {
  align-items: flex-end;
}

.mrg-cluster[data-align="baseline"] {
  align-items: baseline;
}

.mrg-cluster[data-align="stretch"] {
  align-items: stretch;
}

.mrg-cluster[data-justify="center"] {
  justify-content: center;
}

.mrg-cluster[data-justify="end"] {
  justify-content: flex-end;
}

.mrg-cluster[data-justify="between"] {
  justify-content: space-between;
}

.mrg-cluster[data-orphan="fill"] > :last-child {
  flex-grow: 1;
}

import { forwardRef, type HTMLAttributes } from "react";

import "./cluster.css";

export type ClusterGap = "none" | "xs" | "sm" | "md" | "lg";
export type ClusterAlign = "start" | "center" | "end" | "baseline" | "stretch";
export type ClusterJustify = "start" | "center" | "end" | "between";
export type ClusterOrphan = "start" | "fill";

export interface ClusterProps extends HTMLAttributes<HTMLDivElement> {
  readonly gap?: ClusterGap;
  readonly align?: ClusterAlign;
  readonly justify?: ClusterJustify;
  /** `start` keeps an orphan on the logical leading edge; `fill` lets the final item grow. */
  readonly orphan?: ClusterOrphan;
}

function joinClusterClassName(className: string | undefined): string {
  return className === undefined || className.trim().length === 0
    ? "mrg-cluster"
    : `mrg-cluster ${className}`;
}

export const Cluster = forwardRef<HTMLDivElement, ClusterProps>(function Cluster(
  { align = "center", className, gap = "sm", justify = "start", orphan = "start", ...nativeProps },
  forwardedRef,
) {
  return (
    <div
      {...nativeProps}
      ref={forwardedRef}
      className={joinClusterClassName(className)}
      data-align={align}
      data-gap={gap}
      data-justify={justify}
      data-orphan={orphan}
      data-slot="cluster"
    />
  );
});

Cluster.displayName = "Cluster";

export { Cluster } from "./cluster";
export type {
  ClusterAlign,
  ClusterGap,
  ClusterJustify,
  ClusterOrphan,
  ClusterProps,
} from "./cluster";
